catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    // Clear existing options
    g_form.clearOptions('sub_sub_category');
    g_form.addOption('sub_sub_category', '', '-- Select Sub-Sub Category --');

    if (!newValue) return;

    // Map of Sub-Category → Sub-Sub Category
    var subSubMap = {
        'UTP Cable': ['d-link-utp 4-pair', 'Schneider-utp 4-pair'],
        'STP Cable': ['d-link-stp 4-pair', 'Schneider-stp 4-pair'],
        'Coaxial Cable': ['NPC SODIAL Coaxial Cable', 'CABLESETC Coaxial Cable'],
        'Fiber Optic Cable': ['Belkin 3M Duplex Fiber Optic Cable'],
        'Analog': ['Analog-Model-A', 'Analog-Model-B'],
        'Digital': ['Digital-Model-A', 'Digital-Model-B'],
        'Active': ['Active-Model-A', 'Active-Model-B'],
        'Passive': ['Passive-Model-A', 'Passive-Model-B'],
        'SPST': ['SPST-Model-A', 'SPST-Model-B'],
        'SPDT': ['SPDT-Model-A', 'SPDT-Model-B'],
        'DPST': ['DPST-Model-A', 'DPST-Model-B'],
        'DPDT': ['DPDT-Model-A', 'DPDT-Model-B']
    };

    // Populate Sub-Sub Category if exists
    if (subSubMap[newValue]) {
        g_form.setVisible('sub_sub_category', true);
        var options = subSubMap[newValue];
        for (var i = 0; i < options.length; i++) {
            g_form.addOption('sub_sub_category', options[i], options[i]);
        }
    } else {
        g_form.setVisible('sub_sub_category', false);
    }
}
